var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음… 어디보자… 이걸 누르면 되는 거였나?","JPN":"うん……えっと……ここを押すんだったっけ？","ENG":"Hmm... Let's see... Is this the right button?","TWN":"嗯…我看看…按下這個就好嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 돌아가고 있는 거 같은데 녹화 잘 되고 있는거 맞겠지? ","JPN":"動いているみたいだけど、録画できてるのかな？ ","ENG":"I think something's running. The recording should be fine, right?","TWN":"好像有在動的樣子，應該有在錄吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어흠, 어… 그러니까 오늘 사장의 생일이라고 들었거든.","JPN":"コホン、あ……えっと、今日は社長の誕生日だって聞いて。","ENG":"Ahem, uh... Well, I heard it was your birthday today, Boss.","TWN":"咳咳…聽說今天是老闆的生日。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일축하라… 그런 말을 들어본 게 언제였는지 기억도 가물가물한데.","JPN":"お誕生祝い……なんて言葉聞いたのいつぶりか、よく思い出せないな。","ENG":"I can't really remember the last time I heard someone say happy birthday...","TWN":"生日快樂…我都不記得上次有人對我說這句話是什麼時候了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일… 축하해 사장님. 아하하. 조금 어색하네…….","JPN":"誕生日……おめでと、社長。あはは。ちょっと照れるね……","ENG":"Happy... birthday, Boss. Ah ha ha. This is a little awkward...","TWN":"老闆…生日快樂，哈哈哈，真是尷尬……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이곳에 입사하고 사장의 도움이 있었기에 지금까지 잘 헤쳐나올 수 있었던 것 같아.","JPN":"ここに入社して、社長の助けがあったから、今までうまくやってこれたんだと思う。","ENG":"It was thanks to you that I managed to make it this far.","TWN":"來到這裡之後，因為有老闆的幫忙，我才能關關難過關關過。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단은 고맙다고 말해주고 싶어. 진심으로.","JPN":"とりあえず、ありがとうって言いたかったんだ。心から。","ENG":"So I want to start off by saying thank you. Truly.","TWN":"首先，我想真心地跟老闆說一聲，謝謝。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생일 기념으로 사장실 앞에다 선물도 놔뒀으니 확인해 봐. 내용물은 말하지 않을게.","JPN":"誕生日の記念に社長室の前にプレゼントを置いておいたから、見てみて。どんなものかは言わないでおくよ。","ENG":"I left a birthday gift in front of the CEO's office, so check it out. I won't spoil what's inside.","TWN":"今天是你的生日，禮物就放在老闆辦公室前，你自己去看看吧。至於送什麼禮物我是不會說的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"포장을 뜯어보는 설렘도 중요…….","JPN":"包みを開く時のどきどきも大事……","ENG":"The excitement of unwrapping the gift is also immeasurable–","TWN":"拆禮物時的期待感也是很重要的……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나양? 뭐하고 계신 건가요?","JPN":"ミナさん？　何をしているんですか？","ENG":"Mina? What are you doing?","TWN":"米娜？你在幹嘛？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으앗?! 서, 선배?!","JPN":"うわっ！？　せ、先輩！？","ENG":"W-whoa! Sh-Shiyoon?!","TWN":"蛤？！前…前輩？！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"멀리서 혼잣말로 대화하고 계신 거 같아서 다가가 봤는데 뭘 찍고 계신 건가요?","JPN":"遠くで何やら一人で話しているように見えて近くに来てみたんですが、何を撮っていたんですか？","ENG":"It seemed like you were talking to yourself from afar. What are you filming?","TWN":"我看你好像一個人在自言自語，就過來看一下。你是在拍什麼東西？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그러니까… 딱히 수상한 건 아니야!","JPN":"こ、これは……怪しいものじゃないよ！","ENG":"I-it's... nothing suspicious!","TWN":"那個……我不是在做壞事！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하하. 수상한 행동을 하는 사람들의 단골 멘트네요.","JPN":"ハハハ。怪しい行動をしている人のおきまりのセリフですね。","ENG":"Hah hah hah. That's exactly what a suspicious person would say.","TWN":"哈哈哈，做壞事的人通常都會這麼說。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하. 곧 사장님 생일이니까 기념 영상을 찍어보자고 사내 공지글을 봤었는데 예상대로네요.","JPN":"なるほど。もうすぐ社長の誕生日なので記念動画を撮ろうって社内連絡にありましたが、思っていた通りですね。","ENG":"Aha. I remember seeing the company notice suggesting that we film a congratulations video for Boss's birthday.","TWN":"哈，我有看到公司布告欄上貼的公告說，老闆的生日快到了，要請大家拍祝賀影片，你就是在拍這個吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 그렇게나 사장님을 생각해 주실 줄은 몰랐네요. 이거 다시 보게 되는걸요?","JPN":"ミナさんがそこまで社長の事を考えておられるとは知りませんでした。見直しましたよ。","ENG":"I didn't know you cared about Boss that much. I'm quite surprised.","TWN":"沒想到你對老闆的事如此上心，令人寡目相看呢。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알고 있었잖아! 한참을 기다려도 아무도 안 오길래 먼저 찍고 있던건데……!","JPN":"知ってたんじゃない！　ずっと待ってたのに誰も来ないから、先に撮っていたのに……！","ENG":"You knew about it?! I just started filming because no one came, even though I waited for a long time...!","TWN":"那你還明知故問！我等了半天都沒有人來，想說乾脆我自己先拍……！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기에다 대고 말하면 되는 거죠? 생일 축하드립니다 사장님. 그럼 앞으로도 잘 부탁드릴게요.","JPN":"ここに向かって話したらいいんですよね？　お誕生日おめでとうございます、社長。これからもよろしくおねがいします。","ENG":"Do I speak into this mic? Happy birthday, Boss. Hope you have a great day.","TWN":"對著這邊說話就可以了吧？老闆生日快樂，之後也請多多指教。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};